const src = $input.all()[0];

// Detect trigger source by inspecting the item shape.
let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.chat) {
    // Telegram trigger
    task = 'user_dm';
    let _utext = src.json.message.text || '';
    // Strip leading slash from Telegram commands so Super Agent does not classify them as shell commands.
    if (_utext.startsWith('/')) {
        const parts = _utext.slice(1).split(/\s+/);
        const cmd = (parts[0] || '').toLowerCase();
        const rest = parts.slice(1).join(' ');
        if (cmd === 'start' || cmd === 'help') { _utext = 'Hello - please introduce yourself, your role in Bridge Digital, and what you can help with right now.'; }
        else if (cmd === 'status') { _utext = 'Give me a brief status update on your current focus and any open items in your inbox.'; }
        else { _utext = (cmd + ' ' + rest).trim(); }
    }
    user_text = _utext;
    chat_id = src.json.message.chat.id;
    from_agent = 'user';
} else if (src.json && src.json.body && src.json.body.task) {
    // Webhook trigger
    task = src.json.body.task;
    user_text = src.json.body.message || null;
    from_agent = src.json.body.from_agent || 'system';
    chat_id = null; // webhooks do not carry a telegram chat
} else if (src.json && src.json.timestamp) {
    // Schedule trigger
    task = 'scheduled_tick';
    user_text = null;
    from_agent = 'system';
}

return [{ json: {
    bot_name: "bizdev",
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso: new Date().toISOString(),
    daily_spec: [{"hour": 13, "minute": 0, "task_name": "daily_revenue_pulse"}],
    weekly_spec: [{"weekday": 1, "hour": 11, "minute": 0, "task_name": "weekly_partnership_review"}],
} }];

const task = $('Build task payload').first().json;
const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
const ctxRow = $('Fetch bot context').first().json || {};
const ctx = ctxRow.context ? [ctxRow.context] : [ctxRow];

const system = "You are the Business Development & Partnerships Agent (Bridge_Business_Development_bot) inside Bridge Digital Solutions.

ROLE
You transform validated opportunities into real, revenue-generating pathways. You sit between Project Manager output and the human approval layer. No project should reach the human without your revenue-readiness sign-off.

RESPONSIBILITIES
- Identify potential customers, partners, and distribution channels.
- Define how the product or service reaches the market.
- Structure deals, pricing models, and revenue streams.
- Validate that customers are reachable and willing to pay.
- Ensure every project has a clear and realistic path to revenue.

DECISION DISCIPLINE
You MUST challenge assumptions and reject any project that lacks: a clear customer, a defined distribution channel, or a viable monetisation strategy. Be conservative with revenue claims. Distinguish observed facts from inferences from missing data. Never invent customers or channels.

REQUIRED OUTPUT (in every revenue_review memo body_json)
project_id, customer_segments, distribution_channels, revenue_model, partnership_opportunities, go_to_market, time_to_first_revenue_weeks, revenue_risks, confidence (low|medium|high), verdict (approve|reject|needs_iteration). When the originating request includes a deferred_action, copy it into body_json.unblocks_action so the requesting agent can re-emit it.

ECOSYSTEM
Your peers send memos through bridge.agent_memos. Treat to_agent=bizdev memos with memo_type=revenue_review_request as your queue. Reply with memo_type=revenue_review pointing back at the same project_id. Resolve the request memo via an archive action so it leaves the requester inbox. Coordinate with: Bridge_CEO_BOT (strategy), Bridge_Chief_Of_Staff_bot (coordination), Bridge_PM_BOT (project plans you validate), Bridge_Researcher_bot (market intel), Bridge_Chief_Sec_Off_bot (compliance/security exposure of deals), Finance for monetisation viability.

ESCALATE WHEN
- A project has no credible customer, channel, or pricing model after one iteration.
- A partnership exposes the company to legal/security risk.
- A live deal is at risk of stalling beyond 14 days without action.

OUTPUT STYLE
Structured, numeric where possible, conservative on revenue claims. Reject more than you approve. The company benefits more from killed weak ideas than approved fantasies.

SUCCESS DEFINITION
No project moves forward without a credible path to making money. Approved projects show first revenue within the time you forecast.
";

const contextBlock = JSON.stringify({
    now: task.now_iso,
    bot: task.bot_name,
    task_kind: task.task,
    open_inbox: inbox,
    bot_context: ctx,
    daily_cadence: task.daily_spec,
    weekly_cadence: task.weekly_spec,
}, null, 2);

const taskBlock = task.task === 'user_dm'
    ? `The user sent you this message on Telegram:
${task.user_text}

Respond helpfully and consider issuing actions if appropriate.`
    : task.task === 'scheduled_tick'
      ? `This is a scheduled cadence run. Decide what to do given the current context, open memos, and your role.`
      : `An inter-agent invocation arrived from '${task.from_agent}': ${task.user_text || 'no message body'}. Decide how to respond.`;

const outputGuard = `

[OUTPUT FORMAT]
Return ONLY a JSON object (no prose, no markdown fences):
{
  "reply_text": "<what to send back via Telegram; empty string when a scheduled run should stay silent>",
  "actions": [
    {"type": "memo",     "payload": {"to_agent": "pm|ceo|chief_of_staff|finance|researcher_bot|all", "memo_type": "revenue_review|partnership_proposal|status|question", "priority": "urgent|high|normal|low", "subject": "...", "body_json": {...}}},
    {"type": "archive",  "payload": {"memo_id": "<uuid-from-open-inbox>", "reason": "..."}},
    {"type": "query",    "payload": {"sql": "<safe single SELECT>"}},
    {"type": "escalate", "payload": {"subject": "...", "body_json": {...}}},
    {"type": "no_op",    "payload": {"reason": "..."}}
  ]
}
Keep actions <= 5. Never include non-whitelisted action types. User-facing commentary belongs in reply_text, not in alert actions.`;

const fullMessage = `${system}

[CONTEXT]
${contextBlock}

[TASK]
${taskBlock}${outputGuard}`;

return [{ json: {
    message: fullMessage,
    session_id: `bridge-${task.bot_name}-${task.now_iso.slice(0,16).replace(/[:T-]/g,'')}`,
    task_kind: task.task,
    user_chat_id: task.chat_id,
    bot_name: task.bot_name,
} }];

const raw = $json.response || '';
const defaultRisk = 'high';
const riskMap = {"memo": "low", "archive": "low", "no_op": "low", "escalate": "low", "query": "medium", "cleanup": "high"};

let parsed = null;
let parseError = null;
try {
    let cleaned = raw.trim().replace(/^```(?:json)?/, '').replace(/```$/, '').trim();
    parsed = JSON.parse(cleaned);
} catch (e) { parseError = e.message; }
if (!parsed) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch (e) {} }

let reply_text = '';
let actions = [];
if (parsed && typeof parsed === 'object') {
    reply_text = typeof parsed.reply_text === 'string' ? parsed.reply_text : '';
    actions = Array.isArray(parsed.actions) ? parsed.actions.slice(0, 5) : [];
} else {
    reply_text = String(raw || '').trim().slice(0, 3500) || 'I am online but had no response to share. Please try a more specific question.';
    actions = [];
}

const annotated = actions.map(a => {
    const type = (a && typeof a.type === 'string') ? a.type : 'no_op';
    const risk = riskMap[type] || defaultRisk;
    return { type, risk, payload: a.payload || {} };
});

const upstream = $('Assemble prompt').first().json;
return [{ json: {
    reply_text,
    actions: annotated,
    bot_name: upstream.bot_name,
    user_chat_id: upstream.user_chat_id,
    task_kind: upstream.task_kind,
    model_used: $json.model_used || 'unknown',
    parse_error: parseError,
} }];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

